source .venv/bin/activate && python3 << 'EOF'
# Test the gate_status merge reducer

from src.state import initial_state

state = initial_state()

# gate_status has: Annotated[dict[GateID, GateStatus], lambda a, b: {**a, **b}]
# This is a merge reducer that does {**a, **b}

gate1_update = {"gate_status": {"gate_1": {"decision": "approved"}}}
gate2_update = {"gate_status": {"gate_2": {"decision": "rejected"}}}

# Simulate merging
state["gate_status"] = {**state["gate_status"], **gate1_update["gate_status"]}
state["gate_status"] = {**state["gate_status"], **gate2_update["gate_status"]}

print("After merging two gate updates:")
print(state["gate_status"].keys())

# Test concurrent-ish writes (same gate updated twice)
gate1_v1 = {"gate_status": {"gate_1": {"decision": "approved", "timestamp": "t1"}}}
gate1_v2 = {"gate_status": {"gate_1": {"decision": "rejected", "timestamp": "t2"}}}

state2 = initial_state()
state2["gate_status"] = {**state2["gate_status"], **gate1_v1["gate_status"]}
state2["gate_status"] = {**state2["gate_status"], **gate1_v2["gate_status"]}

print("\nAfter updating same gate twice:")
print("Final decision:", state2["gate_status"]["gate_1"]["decision"])
print("This is LAST-WRITE-WINS, which could lose data if two updates happen concurrently!")

print("\nHowever, per the comment in gate_coordinator.py:")
print("  'Each gate writes a unique gate_id key'")
print("  And per state.py comment: 'LangGraph merges it into existing dict'")
print("\nThe protection is that each GATE can only write once (its own key).")
print("LangGraph checkpoint system ensures serialized writes.")
EOF

